// OpenUI Lang (thesys), the real one — our single most important rival.
//
// This file used to THROW. It was a placeholder that said, in as many words, "we
// have not read the spec, and a caricature that loses is worse than no data".
// The spec has now been read, their package is installed (@openuidev/lang-core,
// MIT), and every word of this arm's system prompt is generated by THEIR OWN
// prompt generator over OUR catalog — the like-for-like experiment
// docs/internal/research/rival-formats.md asks for.
//
// THE ONE THING TO UNDERSTAND ABOUT THIS ARM: it has a content-avoidance
// mechanism, and it is turned ON. See evals/catalog/openui-tools.ts. `Query()` is
// OpenUI's answer to parchment's reference, it is in their shipped grammar, and
// their own generated prompt orders the model to use it ("NEVER hardcode tool
// results as literal arrays or objects"). Handing this arm the toolless prompt
// they happen to have checked into their benchmarks directory would have won us
// the comparison by omission.
//
// It authors through canvas_render's `markup` string field, which is simply the
// tool's slot for "a text document". No arm's tool SCHEMA differs — that schema is
// input tokens every canvas arm pays identically, and changing it for one arm
// would put a thumb on the input scale.

import { ArmId, AuthoringSurface, Fidelity, type Arm, type EvalScenario } from "../types.ts";
import { createParchmentOpenUiLibrary } from "../catalog/openui-library.ts";
import { OPENUI_TOOL_SPECS } from "../catalog/openui-tools.ts";
import { buildRepairPrompt } from "./repair-prompt.ts";
import { buildTaskPrompt } from "./task-encoding.ts";

// Their generator, called as their docs call it. `toolCalls` turns on Query,
// Mutation and the Data Workflow section; `bindings` turns on $state. Both are
// what OpenUI ships when a host provides tools, and a host that provides none is
// not OpenUI at its best.
function buildOpenUiSystemPrompt(): string {
  const library = createParchmentOpenUiLibrary();
  const vendorPrompt = library.prompt({
    tools: [...OPENUI_TOOL_SPECS],
    toolCalls: true,
    bindings: true,
  });

  return [vendorPrompt, "", TRANSPORT_SECTION].join("\n");
}

// The ONLY text in this prompt that OpenUI did not write. It says where to put the
// document, and nothing about how to author it — their generator has already said
// all of that, including the rule that the model must not paste tool results.
const TRANSPORT_SECTION = [
  "## Output",
  "",
  "Send the openui-lang program to the canvas_render tool as { title, markup }. The `markup`",
  "argument carries the program text. Send the program and nothing else — no prose, no fences.",
].join("\n");

// The task, in the same words every other arm gets. The closing paragraph states
// this arm's capability as a FACT and never as advice: it may read the files, and
// its renderer can also fetch them through a Query. Telling it to "prefer Query"
// would be telling the model the answer we are trying to measure — and the same
// restraint is what parchment's own high arm is held to.
const OPENUI_AUTHORING_INSTRUCTION =
  "You can read the files above with Read. The page can also point at a file: the tools listed " +
  "in your system prompt are available to Query(), and the host reads the file at render time.";

export const openUiLangArm: Arm = {
  id: ArmId.OpenUiLang,
  // High, and the word is earned: Query() is a genuine reference mechanism, so
  // this arm stands on the same rung parchment's high arm stands on.
  fidelity: Fidelity.High,
  surface: AuthoringSurface.CanvasTool,
  systemPrompt: buildOpenUiSystemPrompt(),
  encodeTask: (scenario: EvalScenario) => buildTaskPrompt(scenario, OPENUI_AUTHORING_INSTRUCTION),
  repairPrompt: buildRepairPrompt,
};
